@startuml
title BADEXAMPLE's Class Diagram

package solid {
  package interfacesegregation {
    package badexample {

      class AContainer {
        +AContainer()
        +doYourContainerStuffToMe()
      }

      class AMachine {
        +AMachine()
        +doSomeWork()
      }

      class MUser {
        +MUser()
        +doYourOperations()
      }

      class Operations {
        +operation1()
        +operation2()
        +operation3()
      }

      AContainer o-- Operations : ops
      AMachine o-- Operations : ops
      MUser o-- Operations : ops
    }
  }
}
@enduml
